def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    primes_cache = {}
    def is_prime(n):
        if n < 2:
            return False
        if n in primes_cache:
            return primes_cache[n]
        for x in range(2, int(n**0.5) + 1):
            if n % x == 0:
                primes_cache[n] = False
                return False
        primes_cache[n] = True
        return True
    def complex_factor(x):
        val = 0
        for p in range(1, 10):
            val += np.tanh(np.sin(x * p * 0.8) + np.cos(x / (p + 1))) * (p ** 1.1)
        return val
    def nested_series(r):
        s = 0
        for i in range(1, 10):
            inner_sum = 0
            for j in range(1, i+1):
                inner_sum += ((-1)**(j)) * (r**j) / (j**1.5 + 1)
            s += np.exp(-i*r) * inner_sum
        return s
    for idx, cap in enumerate(bins):
        if cap == 0:
            priorities[idx] = np.inf if item > 0 else 500
            continue
        if cap < 0:
            priorities[idx] = -np.inf
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.1:
            for a in range(1, 10):
                wave = np.sin(cap * 0.7 + a*ratio*3) * np.cos(a * ratio * 5)
                score += (wave + 1.2) * (np.log1p(cap + a) + a) / (a * 2 + 1)
            for b in range(1, int(cap)+1):
                if (cap % b == 0) and (is_prime(b) or b % 5 == 2):
                    score += (b ** 0.6) * 1.5
            if cap % 7 == 0:
                score *= 1.13
            if int(cap) % 4 == 0:
                score += np.sqrt(cap) * 2.2
        elif 0.1 <= ratio < 0.3:
            base = np.sin(ratio * np.pi * 6) * 25
            series = 0
            for c in range(1,8):
                series += ((-1)**(c+1)) * np.log1p(ratio*c) / c
            score += base + series * 8
            divisible_bonus = 0
            for d in [2,5,8,10]:
                if cap % d == 0:
                    divisible_bonus += d * 0.7
            if divisible_bonus > 0:
                score += divisible_bonus * 1.1
            if int(cap) % 6 == 0:
                score *= 0.9
        elif 0.3 <= ratio <= 0.6:
            sine_part = np.sin(ratio * np.pi * 7) * 18
            factorial_series = 0
            for e in range(1, 10):
                fact = np.math.factorial(e)
                factorial_series += ((-1)**(e+1))*(ratio**e)/fact * e * 1.5
            score += sine_part + factorial_series
            for g in range(3, int(min(15, cap))):
                if cap % g == 0 and g % 3 == 2:
                    score += np.sqrt(g) * 3
            if int(cap) % 9 == 0:
                score *= 0.85
        elif 0.6 < ratio <= 0.85:
            logistic = 40 / (1 + np.exp(-30 * (ratio - 0.75)))
            score += logistic
            prime_sum = 0
            for h in range(2, 15):
                if is_prime(h) and h % 4 == 3:
                    prime_sum += h * 1.1
            score += prime_sum
            if ratio > 0.82:
                score += (1 - ratio) * 80
            if int(cap) % 8 == 0:
                score *= 0.8
            if int(cap) % 3 == 0:
                score += 12
        elif 0.85 < ratio < 1.2:
            penalty = 0
            chunk = max(1, int(cap//4))
            for i in range(1, chunk+1):
                if cap % i == 0:
                    penalty += i ** 1.5
            fract = ratio - int(ratio)
            for j in range(1, 10):
                mod_val = (fract * j * 900) % 7
                penalty += (mod_val / 7) * 7
            score += penalty / (chunk + 3)
            score += (ratio - 1) * (-45)
            if cap % 13 == 0:
                score *= 0.9
            if int(cap) % 11 == 0:
                score += 20
            if int(cap) % 14 == 0:
                score *= 0.78
        elif 1.2 <= ratio <= 3:
            complex_sum = 0
            for k in range(1, int(min(20, cap))):
                if cap % k == 0:
                    if k % 3 == 0:
                        complex_sum += np.log1p(k) * 3.5
                    else:
                        complex_sum += np.sqrt(k) * 2.8
            fract_part = ratio - int(ratio)
            for m in range(1, 12):
                complex_sum += np.sin(fract_part * m * np.pi) * 2.5
            score += complex_sum
            score += (ratio - 2) * 65
            if ratio > 2.5:
                for n in range(1, int(cap//4)+1):
                    if n % 5 == 0:
                        score += np.cos(n*1.5) * 3.5
            if int(cap) % 10 == 0:
                score *= 1.1
            if int(cap) % 16 == 0:
                score *= 0.7
        else:
            sum_val = 0
            for p in range(1, int(min(25, cap))):
                if cap % p == 0:
                    sum_val += complex_factor(p)
            fract_part = (ratio - int(ratio)) * 5
            for q in range(1, 15):
                sum_val += np.tanh(fract_part * q) * 3
            score += sum_val
            score += (ratio - 3) * 75
            if ratio > 5:
                for r in range(1, int(cap//2)+1):
                    if r % 8 == 0:
                        score += np.sin(r*0.7) * 5
            if int(cap) % 20 == 0:
                score *= 0.65
        if int(cap) % 7 == 0 and ratio < 2:
            score *= 1.12
        if int(cap) % 9 == 0 and ratio > 1:
            score *= 0.82
        if ratio > 4 and int(cap) % 15 == 0:
            score += 25
        if int(cap) % 18 == 0:
            score *= 0.79
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 400)
    return priorities
